const { app } = require('@azure/functions');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY || 'SG.azure_demo_key_123';
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID || 'AC1234567890abcdef';
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN || 'twilio_auth_token_placeholder';
const TWILIO_FROM_NUMBER = process.env.TWILIO_FROM_NUMBER || '+10000000000';
const DEFAULT_FROM_EMAIL = process.env.DEFAULT_FROM_EMAIL || 'no-reply@example.com';

sgMail.setApiKey(SENDGRID_API_KEY);

const twilioClient = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

app.http('notify', {
  methods: ['POST'],
  authLevel: 'anonymous',
  handler: async (request, context) => {
    try {
      const body = await request.json();

      const type = body.type;
      const to = body.to;
      const subject = body.subject || 'Notification';
      const message = body.message || '';

      if (!type || !to || !message) {
        return {
          status: 400,
          jsonBody: {
            error: 'Missing required fields: type, to, message'
          }
        };
      }

      if (type === 'email') {
        const msg = {
          to,
          from: body.from || DEFAULT_FROM_EMAIL,
          subject,
          text: message,
          html: body.html || `<p>${escapeHtml(message)}</p>`
        };

        await sgMail.send(msg);

        return {
          status: 200,
          jsonBody: {
            success: true,
            channel: 'email',
            to
          }
        };
      }

      if (type === 'sms') {
        const result = await twilioClient.messages.create({
          body: message,
          from: body.from || TWILIO_FROM_NUMBER,
          to
        });

        return {
          status: 200,
          jsonBody: {
            success: true,
            channel: 'sms',
            to,
            sid: result.sid
          }
        };
      }

      return {
        status: 400,
        jsonBody: {
          error: "Invalid type. Use 'email' or 'sms'."
        }
      };
    } catch (error) {
      context.error(error);

      return {
        status: 500,
        jsonBody: {
          error: 'Failed to send notification',
          details: error.message
        }
      };
    }
  }
});

function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}